layer_change_gcode:
{if timelapse_type == 1} ; timelapse with wipe tower
G92 E0
G1 E-[retraction_length] F1800
{if layer_z + 0.4 > max_print_height}
G2 Z{max_print_height} I0.86 J0.86 P1 F20000 ; spiral lift a little
{else}
G2 Z{layer_z + 0.4} I0.86 J0.86 P1 F20000 ; spiral lift a little
{endif}
MOVE_TO_TRASH
{if layer_z <=25}
G1 Z25
{endif}
G92 E0
M400
TIMELAPSE_TAKE_FRAME
G1 E[retraction_length] F300
G1 X180 F8000
G1 Y380
{if layer_z <=25}
G1 Z[layer_z]
{endif}
{elsif timelapse_type == 0} ; timelapse without wipe tower
TIMELAPSE_TAKE_FRAME
{endif}
G92 E0
SET_PRINT_STATS_INFO CURRENT_LAYER={layer_num + 1}

machine_end_gcode:
SET_PRINT_MAIN_STATUS MAIN_STATUS=print_end
DISABLE_BOX_HEATER
M141 S0
M140 S0
DISABLE_ALL_SENSOR
G1 E-3 F1800
{if max_layer_z + 3 > max_print_height}
G0 Z{max_print_height} F600
{else}
G0 Z{max_layer_z + 3} F600
{endif}
UNLOAD_FILAMENT T=[current_extruder]
G0 Y160 F12000
G0 X99 Y170 F12000
{if max_layer_z < max_print_height / 2}
G1 Z{max_print_height / 2 + 10} F600
{else}
G1 Z{min(max_print_height, max_layer_z + 3)}
{endif}
M104 S0
PRINT_END
